  for(let c=0;c<NC;c++){{
    cctx.strokeStyle=colors[c];cctx.lineWidth=2;
    cctx.beginPath();
    for(let i=0;i<n;i++){{
      let x=10+(i/(n-1||1))*680, y=190-(sizes[i][c]/maxS)*170;
